import React from 'react';
import { motion } from 'framer-motion';

const skills = [
  'JavaScript',
  'React',
  'Node.js',
  'CSS',
  'HTML'
];

const Skills = () => {
  return (
    <div className="skills-grid">
      {skills.map((skill, index) => (
        <motion.div
          key={index}
          className="skill-card"
          whileHover={{ scale: 1.1 }}
          transition={{ duration: 0.3 }}
        >
          <h3>{skill}</h3>
        </motion.div>
      ))}
    </div>
  );
};

export default Skills;